import React from "react";
import Typography from "@mui/material/Typography";
import Button from "@mui/material/Button";
import Container from "@mui/material/Container";
import Stack from "@mui/material/Stack";
import TextField from "@mui/material/TextField";
import Grid from "@mui/material/Grid";
import facebookicon from './images/facebookicon.png';
import instagramicon from './images/instagramicon.png';
import twittericon from './images/twittericon.png';


function Contact() {
  return (
    <Stack direction="column" spacing={2} sx={{ bgcolor: "primary.light", padding: "2rem", borderRadius: "8px", border: "1px solid", borderColor: "primary.dark" }}>
      <Typography color="primary" variant="h2" sx={{ color: "primary.contrastText", textAlign: "center", fontWeight: "bold" }}>
        Contact
      </Typography>

      <Stack direction="column" spacing={2}>  
        <Container maxWidth="lg">         
          <Typography color="primary" variant="h3" sx={{ color: "primary.contrastText", textAlign: "center", marginBottom: "1rem" }}>
            Get in Touch
          </Typography> 
          <Stack component="form" spacing={2} sx={{ marginTop: "1rem", maxWidth: "60%", margin: "0 auto" }}>
              <TextField label="Full Name" variant="outlined" fullWidth required />
              <TextField label="Contact Email" type="email" variant="outlined" fullWidth required />
              <TextField label="Subject" variant="outlined" fullWidth required />
              <TextField label="Message" variant="outlined" fullWidth multiline rows={4} required />
              <Button variant="contained" type="submit" sx={{ bgcolor: "secondary.dark", color: "primary.light", maxWidth: "10rem", padding: "0.5rem"}}>
                Submit
              </Button>
            </Stack>
        </Container>
        <Container maxWidth="lg">
           <Grid item xs={12} sm={6} sx={{ maxWidth: "80%" , margin: "0 auto" }}>
              <Typography variant="body1" sx={{ marginBottom: "0.5rem", textAlign: "center" }}>
                <strong>Follow us</strong>
              </Typography>
              <Stack direction="row" spacing={2} justifyContent="center">
                <a href="https://www.facebook.com/" target="_blank" rel="noopener noreferrer" style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                  <img src={facebookicon} alt="Facebook icon" style={{ width: "32px", height: "32px" }} />Facebook</a>
                <a href="https://www.instagram.com/" target="_blank" rel="noopener noreferrer" style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                  <img src={instagramicon} alt="Instagram icon" style={{ width: "36px", height: "36px" }} />Instagram</a>
                <a href="https://twitter.com/" target="_blank" rel="noopener noreferrer" style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                  <img src={twittericon} alt="Twitter icon" style={{ width: "36px", height: "36px" }} />Twitter</a>
              </Stack>
            </Grid>
      </Container>
      </Stack>
    </Stack>
  );
}

export default Contact;