import React from "react";
import { NavLink } from "react-router-dom";
import { AppBar, Toolbar,Tabs, Tab, Button, useMediaQuery, useTheme } from "@mui/material";
import DrawerCorp from "./Drawer.jsx";


function Nav() {
  const theme = useTheme();
  const isMatch = useMediaQuery(theme.breakpoints.down("md"));  
  return (<div>
      <AppBar position="static">
        <Toolbar>
        <img width="50" height="50" src="https://img.icons8.com/dotty/80/bakery--v2.png" alt="bakery logo"/>
        {isMatch ? (          
          <DrawerCorp />          
        ) : (          
          <><Tabs>
              <NavLink to="/" textColor="primary.light">
                <Tab label="Home" />
              </NavLink>
              <NavLink to="/about">
                <Tab label="About" />
              </NavLink>
              <NavLink to="/contact">
                <Tab label="Contact" />
              </NavLink>
            </Tabs>
            <Button variant="contained" sx={{ marginLeft: "auto" }}>
              Log in
            </Button></>
        )}
        </Toolbar>
      </AppBar>  
      </div>  
    );
}

export default Nav;
