import React from "react";
import Typography from "@mui/material/Typography";
import Button from "@mui/material/Button";
import Container from "@mui/material/Container";
import Stack from "@mui/material/Stack";
import Box from "@mui/material/Box";

function Home() {
  return (
    <Stack direction="column" spacing={2} sx={{ bgcolor: "primary.light", padding: "2rem", borderRadius: "8px", border: "1px solid", borderColor: "primary.dark" }}>
      <Container maxWidth="false">
        <Typography color="contrastText" variant="h2" component="h3" sx={{ textAlign: "center", marginBottom: "1rem" }}>
          Welcome to "Sweet Memory" Bakery
        </Typography>
        <Box component="img" src="https://images.unsplash.com/photo-1578985545062-69928b1d9587?w=800" alt="Sweet Memory Bakery" sx={{ width: "100%", height: "400px", objectFit: "cover", borderRadius: "8px", marginBottom: "1rem" }} />
        <Container maxWidth="lg">
          <Typography variant="body1" sx={{ marginBottom: "1rem" }}>
            Ut totam itaque nobis maxime. Deleniti nesciunt culpa perspiciatis a enim alias temporibus officiis ipsum, quos placeat minus perferendis architecto tempora! 
          </Typography>
          <Typography variant="body1" sx={{ marginBottom: "1rem" }}>
            Earum nobis cumque at quisquam itaque architecto, dicta rerum quas, fugit, deleniti minima saepe eveniet.
          </Typography>
          <Typography variant="body1" sx={{ marginBottom: "1rem" }}>
            Officiis delectus odio maxime illum deleniti a natus mollitia, eaque nihil ab eius quae accusantium asperiores nisi eligendi, obcaecati doloribus maiores ratione! 
          </Typography>
          <Typography variant="body1" sx={{ marginBottom: "1rem" }}>
            Consequuntur a libero explicabo voluptatum delectus recusandae obcaecati labore, molestias animi alias tempore magni eveniet eligendi beatae nam.
          </Typography>
          <Button variant="contained" sx={{ bgcolor: "secondary.dark", color: "primary.light", marginTop: "1rem", maxWidth: "50%", margin: "0 auto", display: "block" }}>            
            <a href="about" style={{ color: "inherit", textDecoration: "none" }}>Order Now</a>
          </Button>
        </Container>
      </Container>
    </Stack>
  );
}

export default Home;
